class Vector{constructor({x:x=0,y:y=0}){this.x=x,this.y=y}static formOffsets(info){return new Vector({x:info.offsetX,y:info.offsetY})}static zero(){return new Vector({})}static load(data){return new Vector(data)}static mid(vectors){const minX=Math.min(...vectors.map((p=>p.x))),maxX=Math.max(...vectors.map((p=>p.x))),minY=Math.min(...vectors.map((p=>p.y))),maxY=Math.max(...vectors.map((p=>p.y)));return new Vector({x:minX+(maxX-minX)/2,y:minY+(maxY-minY)/2})}static add(v1,v2){return v1.add(v2)}static subtract(v1,v2){return v1.subtract(v2)}static magnitude(v){return v.magnitude()}static scale(v,scaler){return v.scale(scaler)}static min(v1,v2){v1.min(v2)}static max(v1,v2){v1.max(v2)}static dot(v1,v2){return v1.dot(v2)}static topLeft(vectors){let topLeft=vectors[0];for(const vector of vectors)topLeft=topLeft.min(vector);return topLeft}static bottomRight(vectors){let bottomRight=vectors[0];for(const vector of vectors)bottomRight=bottomRight.max(vector);return bottomRight}static getSignAngle(v1,v2){return Math.atan2(v1.y,v1.x)-Math.atan2(v2.y,v2.x)}static rotateAroundCenter(v,center,angle){let{x:x,y:y}=Vector.subtract(v,center),test1=toXY({dir:angle,mag:x}),test2=toXY({dir:angle,mag:y}),rotated=Vector({x:test1.x-test2.y,y:test2.y-test1.x});return Vector.subtract(rotated,center)}static toXY({dir:dir,mag:mag}){return new Vector({x:mag*Math.cos(dir),y:mag*Math.sin(dir)})}static distance(v1,v2){return v1.subtract(v2).magnitude()}add(v){return new Vector({x:this.x+v.x,y:this.y+v.y})}subtract(v){return new Vector({x:this.x-v.x,y:this.y-v.y})}magnitude(){return Math.sqrt(this.x**2+this.y**2)}scale(scaler){return new Vector({x:this.x*scaler,y:this.y*scaler})}min(v){return new Vector({x:Math.min(this.x,v.x),y:Math.min(this.y,v.y)})}max(v){return new Vector({x:Math.max(this.x,v.x),y:Math.max(this.y,v.y)})}dot(v){return this.x*v.x+this.y*v.y}direction(){return Math.atan2(this.y,this.x)}toPolar(){return{dir:this.direction(),mag:this.magnitude()}}toXY({dir:dir,mag:mag}){return new Vector({x:mag*Math.cos(dir),y:mag*Math.sin(dir)})}}export{Vector};